async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationPath: string[] = [agentId],
  context: ProviderContext[] = [],
  emitDone: boolean = true,
  emitErrors: boolean = true,
): AsyncGenerator<StreamResponse, AgentRunResult> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    const error = `Agent '${agentId}' not found or provider not available`;
    if (emitErrors) yield { type: "error", error };
    return { content: "", error };
  }

  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(
      agentId,
      request,
      command,
      abortController,
      debugMode,
    );
    return { content: "" };
  }
  let accumulatedContent = "";
  let toolSequence = 0;

  // A delegate_task ends one provider turn. Its tool result is added to context and
  // the same agent is invoked again, allowing it to continue the conversation.
  while (true) {
    let delegated = false;
    const providerRequest: ProviderChatRequest = {
      message: request.message,
      sessionId: request.sessionId,
      requestId: request.requestId,
      workingDirectory:
        request.workingDirectory || agentConfig.workingDirectory,
      context,
    };

    for await (const response of provider.executeChat(providerRequest, {
      debugMode,
      abortController,
      temperature: agentConfig.config?.temperature,
      maxTokens: agentConfig.config?.maxTokens,
    })) {
      // Convert provider response to stream response
      const chatRoomMessage = createChatRoomMessage(response, agentId);

      if (chatRoomMessage) {
        // Send as chat room protocol message
        yield {
          type: "claude_json",
          data: {
            type: "chat_room_message",
            message: chatRoomMessage,
            session_id: request.sessionId,
          },
        };
      }

      // Also send original response format for compatibility
      if (response.type === "text") {
        accumulatedContent += response.content || "";
        yield {
          type: "claude_json",
          data: {
            type: "assistant",
            content: response.content,
            model: response.metadata?.model,
          },
        };
      } else if (
        response.type === "tool_use" &&
        response.toolName === "delegate_task"
      ) {
        const toolUseId =
          response.toolUseId || `${agentId}-delegate-${++toolSequence}`;
        const input = response.toolInput;

        if (!isDelegationToolInput(input)) {
          const result = {
            content: "",
            error: "delegate_task requires string agent_id and instructions",
          };
          yield toolUseStreamResponse(
            agentId,
            toolUseId,
            input,
            request.sessionId,
          );
          yield toolResultStreamResponse(toolUseId, result, request.sessionId);
          context.push({
            role: "user",
            content: JSON.stringify({
              type: "tool_result",
              is_error: true,
              content: result.error,
              tool_use_id: toolUseId,
            }),
          });
        } else {
          yield toolUseStreamResponse(
            agentId,
            toolUseId,
            input,
            request.sessionId,
          );
          let result: AgentRunResult;
          if (delegationPath.includes(input.agent_id)) {
            const error = `Circular delegation detected for agent '${input.agent_id}'`;
            yield { type: "error", error };
            result = { content: "", error };
          } else if (
            !globalRegistry.getAgent(input.agent_id) ||
            !globalRegistry.getProviderForAgent(input.agent_id)
          ) {
            const error = `Agent '${input.agent_id}' not found or provider not available`;
            yield { type: "error", error };
            result = { content: "", error };
          } else {
            result = yield* executeSingleAgent(
              input.agent_id,
              { ...request, message: input.instructions },
              null,
              abortController,
              debugMode,
              [...delegationPath, input.agent_id],
              [],
              false,
              false,
            );
          }
          yield toolResultStreamResponse(toolUseId, result, request.sessionId);
          context.push({
            role: "user",
            content: JSON.stringify({
              type: "tool_result",
              is_error: Boolean(result.error),
              content: result.error || result.content || EMPTY_AGENT_RESPONSE,
              tool_use_id: toolUseId,
            }),
          });
        }
        delegated = true;
        break;
      } else if (response.type === "done") {
        if (emitDone) yield { type: "done" };
        return { content: accumulatedContent };
      } else if (response.type === "error") {
        const error = response.error || "Agent execution failed";
        if (emitErrors) yield { type: "error", error };
        return { content: accumulatedContent, error };
      }
    }
    if (!delegated) {
      if (emitDone) yield { type: "done" };
      return { content: accumulatedContent };
    }
  }
}

